<script setup lang="ts">
import { File, Image, MapPin, MoreHorizontal, Paperclip, Search, Send, Smile } from 'lucide-vue-next'
import { computed, ref } from 'vue'
import { conversations } from '@/mock/data'
import type { Message } from '@/types'
const activeId=ref(conversations[0].id); const text=ref(''); const active=computed(()=>conversations.find(c=>c.id===activeId.value)!)
function send(){ if(!text.value.trim())return; active.value.messages.push({id:`m${Date.now()}`,senderId:'u-001',content:text.value,time:'刚刚',mine:true,read:false} as Message); text.value='' }
</script>
<template><div class="container messages-page"><div class="chat-shell"><aside class="conversation-list"><div class="chat-title"><h1>消息</h1><button><MoreHorizontal /></button></div><div class="chat-search"><Search :size="16" /><input placeholder="搜索联系人或小队" /></div><div class="conversations"><button v-for="item in conversations" :key="item.id" :class="{active:item.id===activeId}" @click="activeId=item.id"><span class="avatar"><img :src="item.avatar" /><i v-if="item.online"></i></span><span class="conversation-copy"><b>{{ item.name }}<small>{{ item.lastTime }}</small></b><em>{{ item.lastMessage }}</em></span><strong v-if="item.unread">{{ item.unread }}</strong></button></div></aside><main class="chat-main"><header><div><img :src="active.avatar" /><span><b>{{ active.name }}</b><small>{{ active.type==='小队'?'186 位成员 · 28 人在线':'当前在线' }}</small></span></div><button><MoreHorizontal /></button></header><div class="messages"><div class="date-divider">今天 10:30</div><div v-if="active.type==='小队'" class="announcement">📣 群公告：周六 18:20 桥西游客中心集合，请穿舒服的鞋。</div><div v-for="message in active.messages" :key="message.id" :class="['message',{mine:message.mine}]"><img v-if="!message.mine" src="https://i.pravatar.cc/80?img=45" /><div><p>{{ message.content }}</p><span>{{ message.time }} {{ message.mine?(message.read?'已读':'未读'):'' }}</span></div></div><div v-if="!active.messages.length" class="no-messages">还没有消息，发个招呼吧 👋</div></div><div class="composer"><div class="compose-tools"><button><Smile :size="19" /></button><button><Image :size="19" /></button><button><File :size="19" /></button><button><MapPin :size="19" /></button></div><div class="compose-input"><textarea v-model="text" placeholder="输入消息，按 Enter 发送" @keydown.enter.prevent="send"></textarea><button :disabled="!text.trim()" @click="send"><Send :size="18" /></button></div></div></main><aside class="chat-info"><img :src="active.avatar" /><h3>{{ active.name }}</h3><p>{{ active.type==='小队'?'不赶路的城市散步，欢迎每一个慢热的人。':'在落日散步活动中认识' }}</p><div><span>消息免打扰 <input type="checkbox" /></span><span>置顶会话 <input type="checkbox" checked /></span></div><button>查看{{ active.type==='小队'?'小队主页':'个人主页' }}</button></aside></div></div></template>
